import React, { type FC, type PropsWithChildren, useMemo } from "react";
import { View } from "react-native";
import { uniqueId } from "lodash";
import ErrorMessage from "../ErrorMessage";
import type {IKitsContainer} from "@lmb-it/kitsconcerto-types";
import Addons from "../Addons";
import {
    FormControl,
    FormControlHelper,
    FormControlHelperText,
    FormControlLabelText,
    style as resolveStyle,
} from "@lmb-it/kitsconcertomobile"
import { Label } from "../../../_compat";
import {useComponentDefaults, useResolvedElementStyles} from "@lmb-it/kitsconcerto/hooks";

const KitsContainer: FC<PropsWithChildren<IKitsContainer>> = (rawProps) => {
    const {mergedProps: props, themeStyle, elementStyles: ownElementStyles} = useComponentDefaults('FormContainer', rawProps);
    const {
        id,
        helperText,
        className,
        children,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        required,
        hideError,
        additionalClassName,
        label,
        isFloatedLabel,
        containerStyle,
        disabled,
        elementStyles: parentElementStyles,
    } = props;

    // Merge raw IStyleClasses: FormContainer's own (lower priority) < parent-passed (higher)
    // Then resolve once to platform-appropriate styles
    const elStyles = useResolvedElementStyles(useMemo(() => {
        const merged: Record<string, Record<string, any>> = {};
        const allKeys = new Set([
            ...Object.keys(ownElementStyles || {}),
            ...Object.keys(parentElementStyles || {}),
        ]);
        for (const key of allKeys) {
            merged[key] = {
                ...(ownElementStyles?.[key] || {}),
                ...(parentElementStyles?.[key] || {}),
            };
        }
        return merged;
    }, [ownElementStyles, parentElementStyles]));

    // Generate a unique element ID (for parity with web; not used in native labels)
    const elementId = id ? `${id}_element` : uniqueId("element_");

    // Derive label placement from the label prop
    const placement = useMemo(() => {
        if (label && typeof label === 'object' && 'placement' in label) {
            return label.placement; // "RL" | "B" | "T"
        }
        return "T"; // default: top
    }, [label]);

    // Determine layout direction based on placement
    // T = top (column, label first), B = bottom (column-reverse), RL = side-by-side (row)
    const isHorizontal = placement === "RL";
    const isBottom = placement === "B";

    const labelElement = !isFloatedLabel ? (
        <Label isFormControl label={label} elementId={elementId} required={required} style={elStyles.label || undefined} />
    ) : null;

    const contentElement = (
        <Addons additionalClassName={additionalClassName} leftAddon={leftAddon} rightAddon={rightAddon} invalid={invalid}>
            {children}
        </Addons>
    );



    const themeRnStyle = useMemo(
        () => (themeStyle && Object.keys(themeStyle).length ? resolveStyle(themeStyle) : {}),
        [themeStyle],
    );
    const containerRnStyle = useMemo(
        () => (containerStyle && Object.keys(containerStyle).length ? resolveStyle(containerStyle) : {}),
        [containerStyle],
    );

    return(
        <FormControl
            isInvalid={invalid}
            size="md"
            isDisabled={disabled}
            isReadOnly={disabled}
            isRequired={required}
            style={{width:'100%', gap: 4, ...themeRnStyle, ...containerRnStyle, ...(elStyles.container || {})}}
        >
            {isHorizontal ? (
                <View style={{ flexDirection: 'row', alignItems: 'center', gap: 8, width: '100%' }}>
                    {labelElement}
                    <View style={{ flex: 1 }}>{contentElement}</View>
                </View>
            ) : isBottom ? (
                <>
                    {contentElement}
                    {labelElement}
                </>
            ) : (
                <>
                    {labelElement}
                    {contentElement}
                </>
            )}
            {helperText && typeof helperText !== "function" && <FormControlHelper>
                <FormControlHelperText style={elStyles.helperText || undefined}>
                    {helperText}
                </FormControlHelperText>
            </FormControlHelper>}

            {!hideError && <ErrorMessage invalid={invalid} errors={errors} style={elStyles.error || undefined} />}
        </FormControl>
    )
};

export default KitsContainer;
